import express from "express";
import eggDonorController from "../controllers/eggDonorController.js";
import { requireAdmin, requireAuthenticated } from "../middleware/authMiddleware.js";
const router = express.Router();
router.get("/", requireAuthenticated, eggDonorController.getEggDonors);
router.get("/count", requireAuthenticated, eggDonorController.getEggDonorsCount);
router.post("/", requireAdmin, eggDonorController.createEggDonor);
router.get("/:id", requireAuthenticated, eggDonorController.getEggDonorById);
router.put("/:id", requireAdmin, eggDonorController.updateEggDonor);
router.delete("/:id", requireAdmin, eggDonorController.deleteEggDonor);
export default router;
